const best_url = $('IF URL None').item.json.best_url;
const statusCode = $json.statusCode;
const hasNetworkError = !!$json.error || statusCode === undefined;

// Network error (connection refused, DNS fail, timeout) -> unreachable
if (hasNetworkError) {
  return [{ json: { best_url, _unreachable: true, http_reason: 'connection_error' } }];
}

// 5xx server errors -> unreachable
if (statusCode >= 500) {
  return [{ json: { best_url, _unreachable: true, http_reason: 'server_error_' + statusCode } }];
}

// 403/429 = site is up but blocking bots -> proceed
// 2xx/3xx (n8n follows redirects to final URL) -> proceed
// 404 = specific page missing but domain exists -> proceed (URL validate will judge)
return [{ json: { best_url, _unreachable: false, http_status: statusCode } }];

const baseUrl = 'https://nocodb-production-f802.up.railway.app';
const projectId = 'pb7f1zou786xyqc';
const tableId = 'mey3zgihq7o4at9';
const token = 'SqqM8YcDuzXGijg0oY7PvqTcPX5H-r2sYqbAOWTN';

const tenMinutesAgo = new Date(Date.now() - 10 * 60 * 1000).toISOString();

const getUrl = `${baseUrl}/api/v1/db/data/noco/${projectId}/${tableId}` +
  `?where=(status,eq,processing)~and(UpdatedAt,lt,${encodeURIComponent(tenMinutesAgo)})&limit=100`;

const response = await $helpers.httpRequest({ method: 'GET', url: getUrl, headers: { 'xc-token': token } });
const stuckRows = response.list || [];

for (const row of stuckRows) {
  const patchUrl = `${baseUrl}/api/v1/db/data/noco/${projectId}/${tableId}/${row.Id}`;
  await $helpers.httpRequest({ method: 'PATCH', url: patchUrl, headers: { 'xc-token': token, 'Content-Type': 'application/json' }, body: JSON.stringify({ status: 'pending' }) });
}

return [{ json: { cleanup_count: stuckRows.length } }];

const list = $json.list || [];
if (list.length === 0) {
  return [{ json: { _skip: true, count: 0 } }];
}
// Return all pending IDs as separate items
return list.map(row => ({ json: { Id: row.Id } }));
